## 컨텍스트

Next.js 15 + Prisma + Supabase 스택 전환 프로젝트의 Task 10을 구현한다.

- **프로젝트 루트**: `D:\20. POC\TrmWordDict2`
- **플랫폼**: Windows 11, Bash 사용
- **완료된 태스크**: Task 1~7
- **병렬 진행**: Task 8(Domain)과 Task 9(Word)가 동시에 진행 중. 이 태스크는 `features/term/`, `features/forbidden/`, `app/(admin)/term/`, `app/(admin)/forbidden/` 파일만 작성하므로 충돌 없음.

## 의존 파일 위치 (이미 존재함)
- `lib/prisma.ts` — `export const prisma`
- `lib/auth.ts` — `export async function requireAdmin()`
- `lib/errors.ts` — `export type ActionResult<T>`

---

## Task 10: Term + ForbiddenWord 기능

### [Term] 파일 1: `features/term/schema.ts`

```typescript
import { z } from 'zod'

export const termSearchSchema = z.object({
  keyword: z.string().optional(),
  page: z.coerce.number().default(0),
  size: z.coerce.number().default(20),
})

export const termSaveSchema = z.object({
  termKor: z.string().min(1).max(200),
  termEng: z.string().min(1).max(200),
  termAbbr: z.string().max(100).optional(),
})

export type TermSearchInput = z.infer<typeof termSearchSchema>
export type TermSaveInput = z.infer<typeof termSaveSchema>
```

### [Term] 파일 2: `features/term/queries.ts`

```typescript
import 'server-only'
import { prisma } from '@/lib/prisma'
import type { TermSearchInput } from './schema'

export async function getTerms(params: TermSearchInput) {
  const where = params.keyword
    ? {
        OR: [
          { termKor: { contains: params.keyword } },
          { termEng: { contains: params.keyword, mode: 'insensitive' as const } },
        ],
      }
    : {}

  const [items, total] = await prisma.$transaction([
    prisma.term.findMany({
      where,
      include: { termWords: { include: { word: true }, orderBy: { seqNo: 'asc' } } },
      skip: params.page * params.size,
      take: params.size,
      orderBy: { termKor: 'asc' },
    }),
    prisma.term.count({ where }),
  ])

  return { items, total }
}
```

### [Term] 파일 3: `features/term/actions.ts`

```typescript
'use server'
import { prisma } from '@/lib/prisma'
import { requireAdmin } from '@/lib/auth'
import { termSaveSchema } from './schema'
import type { ActionResult } from '@/lib/errors'

export async function createTerm(input: unknown): Promise<ActionResult<{ id: number }>> {
  await requireAdmin()
  const parsed = termSaveSchema.safeParse(input)
  if (!parsed.success) return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }

  const term = await prisma.term.create({ data: parsed.data })
  return { success: true, data: { id: term.id } }
}

export async function updateTerm(id: number, input: unknown): Promise<ActionResult> {
  await requireAdmin()
  const parsed = termSaveSchema.safeParse(input)
  if (!parsed.success) return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }

  await prisma.term.update({ where: { id }, data: parsed.data })
  return { success: true, data: undefined }
}

export async function deleteTerm(id: number): Promise<ActionResult> {
  await requireAdmin()
  await prisma.term.delete({ where: { id } })
  return { success: true, data: undefined }
}

export async function addTermWord(termId: number, wordId: number, seqNo: number): Promise<ActionResult> {
  await requireAdmin()
  await prisma.termWord.create({ data: { termId, wordId, seqNo } })
  return { success: true, data: undefined }
}

export async function removeTermWord(termId: number, wordId: number): Promise<ActionResult> {
  await requireAdmin()
  await prisma.termWord.delete({ where: { termId_wordId: { termId, wordId } } })
  return { success: true, data: undefined }
}
```

### [Term] 파일 4: `app/(admin)/term/page.tsx`

```typescript
import { getTerms } from '@/features/term/queries'
import { termSearchSchema } from '@/features/term/schema'

export default async function TermPage({
  searchParams,
}: {
  searchParams: Promise<Record<string, string>>
}) {
  const params = termSearchSchema.parse(await searchParams)
  const { items, total } = await getTerms(params)

  return (
    <div>
      <h1 className="text-xl font-bold mb-4">용어 관리</h1>
      <p className="text-slate-500 mb-4">총 {total}건</p>
      <pre className="text-sm bg-slate-100 p-4 rounded">{JSON.stringify(items, null, 2)}</pre>
    </div>
  )
}
```

